@Test
public void testNullDelegateHandling() throws Exception {
    ObjectMapper mapper = new ObjectMapper();
    mapper.disable(SerializationFeature.FAIL_ON_EMPTY_BEANS);
    String ser = mapper.writeValueAsString(new Something());
    Something result = mapper.readValue(ser, Something.class);
    assertNotNull(result);
}

@Test
public void testEmptyObjectSerialization() throws Exception {
    ObjectMapper mapper = new ObjectMapper();
    mapper.disable(SerializationFeature.FAIL_ON_EMPTY_BEANS);
    String json = mapper.writeValueAsString(new Something());
    assertTrue(json.contains("{"));
    assertTrue(json.contains("}"));
}
